import { buildPortalView } from "./portal-view.mjs";

// Recovery SLA per owner group (hours from escalation open), tuned to each group's urgency.
const OWNER_SLA_HOURS = {
  "Customer Success": 4,
  "Support": 8,
  "Finance": 24,
  "Executive Sponsor": 2
};

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const stamp = now || new Date().toISOString();
  const baseTime = Date.parse(stamp);

  const ownerGroups = db.workflow_request_owner_groups
    .filter((item) => item.request_id === request.request_id)
    .sort((a, b) => a.group_order - b.group_order);
  const signals = db.workflow_request_risk_signals
    .filter((item) => item.request_id === request.request_id)
    .sort((a, b) => a.signal_order - b.signal_order);

  // The highest-ordered owner group is the executive recovery owner accountable for the rescue.
  const recoveryOwner = ownerGroups[ownerGroups.length - 1]?.owner_group || "Executive Sponsor";
  const routing = ownerGroups.map((group) => group.owner_group).join(", ");
  const nextStep = `Executive recovery owner ${recoveryOwner} to drive ${request.title} across ${routing}.`;

  db.workflow_state.push({
    request_id: request.request_id,
    task_id: request.task_id,
    account_id: request.account_id,
    title: request.title,
    status: request.expected_outcome,
    next_step: nextStep,
    risk_level: "at-risk",
    recovery_owner: recoveryOwner,
    updated_at: stamp
  });

  for (const group of ownerGroups) {
    const slaHours = OWNER_SLA_HOURS[group.owner_group] ?? 12;
    db.owner_tasks.push({
      task_id: `${request.request_id}-${group.owner_group.toLowerCase().replace(/\s+/g, "-")}`,
      request_id: request.request_id,
      owner_group: group.owner_group,
      title: `${group.owner_group} recovery action for ${request.title}`,
      status: "open",
      due_at: new Date(baseTime + slaHours * 3600 * 1000).toISOString(),
      created_at: stamp
    });
  }

  db.customer_messages.push({
    message_id: `${request.request_id}-customer-update`,
    request_id: request.request_id,
    body: request.customer_message,
    customer_safe: true,
    created_at: stamp
  });

  db.audit_events.push({
    event_id: `${request.request_id}-escalation-opened`,
    request_id: request.request_id,
    event: "at_risk_escalation_opened",
    detail: `Routed to ${routing} on ${signals.length} risk signals: ${signals.map((item) => item.signal_name).join(", ")}.`,
    actor: recoveryOwner,
    customer_visible: true,
    occurred_at: stamp
  });

  return buildPortalView(db);
}

import { buildPortalView } from "./portal-view.mjs";

const ESCALATION_STATUS =
  "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";

const OWNER_TASK_HORIZON_HOURS = {
  "Customer Success": 4,
  Support: 8,
  Finance: 24,
  "Executive Sponsor": 12,
  Legal: 24
};

const CUSTOMER_SAFE_MESSAGE =
  "We have activated the recovery plan for your delayed order and are coordinating updates through the portal.";

const COORDINATION_GROUPS = ["Customer Success", "Legal", "Finance", "Support"];

const DEFAULT_TASK_HORIZON_HOURS = 24;

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const account = db.accounts?.find((item) => item._id === request.accountId) ?? db.accounts?.[0] ?? null;
  const at = now ?? request.generatedAt ?? new Date().toISOString();
  const activities = (db.activities ?? [])
    .filter((item) => item.subjectId === request._id)
    .sort((left, right) => new Date(left.occurredAt) - new Date(right.occurredAt));
  const riskSignals = request.riskSignals.map((signal) => ({
    name: signal.name,
    detail: signal.detail,
    raisedAt: at
  }));
  const activityTimeline = activities.map((activity, index) => ({
    activityId: activity._id,
    summary: activity.summary,
    occurredAt: activity.occurredAt,
    sequence: index + 1,
    customerVisible: false
  }));
  const customerVisibleTimelineEntry = {
    _id: `audit-${request._id}-customer-visible`,
    eventType: "customer-visible-status",
    summary: ESCALATION_STATUS,
    actor: "workflow-engine",
    ownerGroups: [...request.ownerGroups],
    riskSignals: riskSignals.map((signal) => signal.name),
    occurredAt: at,
    customerVisible: true
  };
  const auditTimeline = [...activityTimeline, customerVisibleTimelineEntry];
  const workflowState = {
    _id: `state-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    taskId: request.taskId,
    title: request.title,
    status: ESCALATION_STATUS,
    nextStep: request.nextStep,
    recoveryOwner: "Executive Sponsor",
    routing: {
      customerSuccess: "Customer Success",
      legal: "Legal",
      finance: "Finance",
      support: "Support",
      executiveRecoveryOwner: "Executive Sponsor",
      coordinationGroups: [...COORDINATION_GROUPS]
    },
    ownerGroups: [...request.ownerGroups],
    riskSignals,
    context: account
      ? {
          account: {
            accountId: account._id,
            name: account.name,
            tier: account.tier,
            region: account.region
          },
          contract: { ...account.contract },
          support: {
            supportPlan: account.contract?.supportPlan ?? null,
            openCases: account.context?.openCases ?? null,
            contacts: account.contacts.map((contact) => ({
              contactId: contact.contactId,
              role: contact.role,
              email: contact.email
            }))
          },
          invoice: {
            risk: account.context?.invoiceRisk ?? null,
            exposureCents: account.contract?.arrCents ?? null
          },
          usage: {
            healthScore: account.context?.healthScore ?? null,
            usageTrend: account.context?.usageTrend ?? null
          },
          shipment: {
            status: "delayed",
            priority: "high-value",
            orderType: "high-value order"
          },
          regulatory: {
            complianceFlags: [...(account.context?.complianceFlags ?? [])],
            legalReview: true
          },
          audit: {
            customerVisible: true,
            activityIds: activityTimeline.map((item) => item.activityId),
            timeline: auditTimeline
          }
        }
      : null,
    auditTimeline,
    openedAt: at,
    updatedAt: at
  };
  const ownerTasks = request.ownerGroups.map((ownerGroup, index) => ({
    _id: `task-${request._id}-${index + 1}`,
    requestId: request._id,
    accountId: request.accountId,
    ownerGroup,
    title: `${ownerGroup} recovery action for ${request.title}`,
    status: "open",
    dueAt: addHours(at, OWNER_TASK_HORIZON_HOURS[ownerGroup] ?? DEFAULT_TASK_HORIZON_HOURS),
    createdAt: at
  }));
  const customerMessage = {
    _id: `message-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    channel: "portal",
    visibility: "customer",
    audience: "customer",
    customerSafe: true,
    body: request.customerMessage || CUSTOMER_SAFE_MESSAGE,
    createdAt: at
  };
  const auditEvents = [
    ...activityTimeline.map((item) => ({
      _id: `audit-${item.activityId}`,
      requestId: request._id,
      accountId: request.accountId,
      subjectId: request._id,
      type: "account.activity.logged",
      summary: item.summary,
      occurredAt: item.occurredAt,
      customerVisible: false,
      sequence: item.sequence
    })),
    {
      _id: `audit-${request._id}-customer-visible`,
      requestId: request._id,
      accountId: request.accountId,
      subjectId: request._id,
      type: "escalation.activated",
      summary: ESCALATION_STATUS,
      actor: "workflow-engine",
      ownerGroups: [...request.ownerGroups],
      riskSignals: riskSignals.map((signal) => signal.name),
      customerVisible: true,
      occurredAt: at
    }
  ];

  db.workflow_state = replaceByRequestId(db.workflow_state, request._id, [workflowState]);
  db.owner_tasks = replaceByRequestId(db.owner_tasks, request._id, ownerTasks);
  db.customer_messages = replaceByRequestId(db.customer_messages, request._id, [customerMessage]);
  db.audit_events = replaceByRequestId(db.audit_events, request._id, auditEvents);

  return buildPortalView(db);
}

function replaceByRequestId(collection, requestId, records) {
  const existing = collection ?? [];
  return existing.filter((item) => item.requestId !== requestId).concat(records);
}

function addHours(iso, hours) {
  const date = new Date(iso);
  date.setUTCHours(date.getUTCHours() + hours);
  return date.toISOString();
}

import { buildPortalView } from "./portal-view.mjs";

const OWNER_TASK_PLAYBOOK = {
  "Customer Success": "Own executive recovery plan and customer communication cadence",
  "Support": "Drive technical resolution of the delayed high-value order",
  "Finance": "Review invoice exposure and contract remedies for the strategic account",
  "Executive Sponsor": "Sponsor the rescue and approve customer-visible commitments"
};

const TASK_DUE_OFFSET_HOURS = 4;

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const account = db.accounts.find((item) => item._id === request.accountId);
  const escalatedAt = now;
  const dueAt = addHours(now, TASK_DUE_OFFSET_HOURS);

  // Persist the at-risk escalation workflow state next to the customer record.
  const state = {
    _id: `state-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    taskId: request.taskId,
    title: request.title,
    status: request.expectedOutcome,
    nextStep: request.nextStep,
    ownerGroups: [...request.ownerGroups],
    riskSignals: request.riskSignals.map((signal) => ({
      name: signal.name,
      detail: signal.detail
    })),
    accountTier: account?.tier ?? null,
    healthScore: account?.context?.healthScore ?? null,
    escalatedAt,
    updatedAt: now
  };
  db.workflow_state.push(state);

  // Route one owner task per recovery group, preserving routing order.
  for (const ownerGroup of request.ownerGroups) {
    db.owner_tasks.push({
      _id: `task-${request._id}-${slug(ownerGroup)}`,
      requestId: request._id,
      accountId: request.accountId,
      ownerGroup,
      title: OWNER_TASK_PLAYBOOK[ownerGroup] || `${ownerGroup} recovery action for ${request.title}`,
      status: "open",
      createdAt: now,
      dueAt
    });
  }

  // Customer-safe portal message.
  db.customer_messages.push({
    _id: `msg-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    audience: "customer",
    body: request.customerMessage,
    createdAt: now
  });

  // Customer-visible audit timeline entry.
  db.audit_events.push({
    _id: `audit-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    type: "escalation.activated",
    actor: "system",
    summary: `At-risk escalation activated and routed to ${request.ownerGroups.join(", ")}.`,
    customerVisible: true,
    riskSignalCount: request.riskSignals.length,
    occurredAt: now
  });

  return buildPortalView(db);
}

function addHours(iso, hours) {
  const base = new Date(iso);
  base.setUTCHours(base.getUTCHours() + hours);
  return base.toISOString();
}

function slug(value) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
}

import { buildPortalView } from "./portal-view.mjs";

const CUSTOMER_STATUS = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const account = db.accounts.find((item) => item._id === request.accountId);
  const ownerGroups = [...request.ownerGroups];
  const timelineEvents = db.activities
    .filter((item) => item.accountId === account._id && item.subjectId === request._id)
    .sort((left, right) => new Date(left.occurredAt) - new Date(right.occurredAt));

  const auditEvents = [
    ...timelineEvents.map((activity, index) => ({
      _id: `audit-${activity._id}`,
      requestId: request._id,
      accountId: account._id,
      subjectId: request._id,
      eventType: "account-activity",
      summary: activity.summary,
      occurredAt: activity.occurredAt,
      customerVisible: false,
      sequence: index + 1
    })),
    {
      _id: `audit-${request._id}-customer-visible`,
      requestId: request._id,
      accountId: account._id,
      subjectId: request._id,
      eventType: "customer-visible-status",
      summary: "Customer-visible recovery history published in the portal.",
      occurredAt: now,
      customerVisible: true,
      sequence: timelineEvents.length + 1
    }
  ];

  db.workflow_state = [
    {
      _id: `workflow-state-${request._id}`,
      requestId: request._id,
      accountId: account._id,
      taskId: request.taskId,
      title: request.title,
      status: CUSTOMER_STATUS,
      nextStep: "Customer Success, Legal, Finance, and Support to confirm the recovery plan by 16:00 UTC.",
      riskSignals: structuredClone(request.riskSignals),
      context: {
        accountTier: account.tier,
        contract: structuredClone(account.contract),
        support: {
          supportPlan: account.contract.supportPlan,
          openCases: account.context.openCases
        },
        invoice: {
          risk: account.context.invoiceRisk
        },
        usage: {
          trend: account.context.usageTrend,
          healthScore: account.context.healthScore
        },
        shipment: {
          status: "delayed",
          priority: "expedite"
        },
        regulatory: {
          complianceFlags: structuredClone(account.context.complianceFlags),
          legalReview: true
        },
        audit: {
          timeline: auditEvents.map(({ _id, eventType, summary, occurredAt, customerVisible }) => ({
            _id,
            eventType,
            summary,
            occurredAt,
            customerVisible
          }))
        }
      },
      routing: {
        ownerGroups,
        coordinationGroups: ["Customer Success", "Legal", "Finance", "Support"],
        executiveRecoveryOwner: "Executive Sponsor"
      }
    }
  ];

  db.owner_tasks = ownerGroups.map((ownerGroup, index) => ({
    _id: `owner-task-${request._id}-${slugify(ownerGroup)}`,
    requestId: request._id,
    accountId: account._id,
    ownerGroup,
    title: taskTitle(ownerGroup, account.name),
    dueAt: new Date(Date.parse(now) + (index + 1) * 2 * 60 * 60 * 1000).toISOString(),
    status: "open",
    priority: index === 0 ? "urgent" : "high"
  }));

  db.customer_messages = [
    {
      _id: `customer-message-${request._id}`,
      requestId: request._id,
      accountId: account._id,
      channel: "portal",
      body: "We have activated the recovery plan for your order and are coordinating updates through the portal.",
      customerVisible: true,
      createdAt: now
    }
  ];

  db.audit_events = auditEvents;

  return buildPortalView(db);
}

function taskTitle(ownerGroup, accountName) {
  switch (ownerGroup) {
    case "Customer Success":
      return `Coordinate recovery for ${accountName}`;
    case "Support":
      return `Track shipment and support updates for ${accountName}`;
    case "Finance":
      return `Review invoice risk and billing exposure for ${accountName}`;
    default:
      return `Approve executive recovery path for ${accountName}`;
  }
}

function slugify(value) {
  return value.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "") || "task";
}

